#include <bits/stdc++.h>#include <ext/pb_ds/assoc_container.hpp> // Common file#include <ext/pb_ds/tree_policy.hpp> // Including tree_order_statistics_node_updateusing namespace std;using namespace __gnu_pbds;#ifndef ONLINE_JUDGE#include "debug.cpp"#else#define dbg(...)#endif#define endl "\n"#define FAST ios_base::sync_with_stdio(false); cin.tie(NULL);#define ll long long#define pb(n) push_back(n)#define F first#define S second#define mp(x, y) make_pair(x, y)#define yes cout << "YES" << endl;#define no cout << "NO" << endl;#define nop cout << -1 << endl;#define ordered_set tree<pair<int, int>, null_type, less<pair<int, int>>, rb_tree_tag, tree_order_statistics_node_update>const ll sup = 1e18;const ll inf = -1e18;const ll mod = 1e9 + 7;const int N_Max = 2e5 + 7;const int Nax = 15;const int LOG = 18;const int BITS = 30;const int ALPHA = 26;ll gcd(ll a , ll b) {return b ? gcd(b , a % b) : a;}ll lcm(ll a , ll b) {return (a * b) / gcd(a , b);}ll inv(ll N) {if (N == 1) return 1; return (mod - ((mod / N) * inv(mod % N)) % mod) % mod;} vector<pair<int, int>> adj[N_Max];bool spec[N_Max], sub[N_Max];int mx[N_Max];ll dp[N_Max];int N, K; void dfs_init(int Node, int par){    sub[Node] = spec[Node];    for (auto [child, w] : adj[Node]){        if (child == par) continue;        dfs_init(child, Node);        sub[Node] |= sub[child];    }} void dfs(int Node, int par){    mx[Node] = dp[Node] = 0;    for (auto [child, w] : adj[Node]){        if (child == par || !sub[child]) continue;        dfs(child, Node);        dp[Node] += dp[child];        if (mx[child] < w) dp[Node] += w - mx[child];        mx[Node] = max({mx[Node], w, mx[child]});    }    if (spec[Node]) mx[Node] = 0;} void solve(){    cin >> N;    for (int i = 1; i <= N; i++){        spec[i] = false;        adj[i].clear();    }    for (int i = 1; i < N; i++){        int u, v, w;        cin >> u >> v >> w;        adj[u].push_back({v, w});        adj[v].push_back({u, w});    }    cin >> K;    for (int i = 1; i <= K; i++){        int u;        cin >> u;        spec[u] = true;    }    dfs_init(1, 0);    dfs(1, 0);    cout << dp[1] << endl;} int main(){    FAST    #ifndef ONLINE_JUDGE    freopen("input.txt","r",stdin);    freopen("output.txt","w",stdout);    #endif    freopen("nodes.in","r",stdin);    int tc = 1;    cin >> tc;    while (tc--) solve();    return 0;}